const input = $input.first().json;
const query = input.query || {};
const { code, shop, state } = query;

const SUPABASE_URL = 'https://prometeix-servidor-supabase.reyl9a.easypanel.host/rest/v1';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyAgCiAgICAicm9sZSI6ICJzZXJ2aWNlX3JvbGUiLAogICAgImlzcyI6ICJzdXBhYmFzZS1kZW1vIiwKICAgICJpYXQiOiAxNjQxNzY5MjAwLAogICAgImV4cCI6IDE3OTk1MzU2MDAKfQ.DaYlNEoUrrEn2Ig7tqibS-PHK5vgusbcbo7X36XVt4Q';
const sbHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'Content-Type': 'application/json'
};

const APP_URL = 'https://katalync.com/app';

try {
  if (!code || !shop || !state) {
    return [{ json: { error: true, html: '<h1>Error: Missing parameters</h1>' } }];
  }

  // Decode state: base64-encoded JSON with vendor_id, user_id, client_id, client_secret
  let stateData;
  try {
    stateData = JSON.parse(Buffer.from(state, 'base64').toString('utf-8'));
  } catch (e) {
    return [{ json: { error: true, html: '<h1>Error: Invalid state parameter</h1>' } }];
  }

  const { vendor_id, client_id, client_secret } = stateData;
  if (!vendor_id || !client_id || !client_secret) {
    return [{ json: { error: true, html: '<h1>Error: Missing vendor or credentials in state</h1>' } }];
  }

  // Exchange code for access token
  const tokenResp = await fetch(`https://${shop}/admin/oauth/access_token`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      client_id: client_id,
      client_secret: client_secret,
      code: code
    })
  });

  if (!tokenResp.ok) {
    const errText = await tokenResp.text();
    return [{ json: { error: true, html: `<h1>Error getting token from Shopify</h1><p>${errText.substring(0, 200)}</p>` } }];
  }

  const tokenData = await tokenResp.json();
  const accessToken = tokenData.access_token;

  if (!accessToken) {
    return [{ json: { error: true, html: '<h1>Error: No access token received from Shopify</h1>' } }];
  }

  // Save access token to vendor in Supabase
  const updateResp = await fetch(`${SUPABASE_URL}/vendors?id=eq.${vendor_id}`, {
    method: 'PATCH',
    headers: { ...sbHeaders, 'Prefer': 'return=representation' },
    body: JSON.stringify({
      source_api_key: accessToken,
      source_url: `https://${shop}`,
      sync_status: 'connected',
      config: { oauth_scope: tokenData.scope || '', connected_at: new Date().toISOString() }
    })
  });

  if (!updateResp.ok) {
    const errText = await updateResp.text();
    return [{ json: { error: true, html: `<h1>Error saving token</h1><p>${errText.substring(0, 200)}</p>` } }];
  }

  // Test the token by fetching shop info
  let shopName = shop;
  try {
    const shopResp = await fetch(`https://${shop}/admin/api/2024-01/shop.json`, {
      headers: { 'X-Shopify-Access-Token': accessToken }
    });
    if (shopResp.ok) {
      const shopData = await shopResp.json();
      shopName = shopData.shop?.name || shop;
    }
  } catch(e) {}

  // Return success HTML that redirects to Katalync
  const html = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"><title>Conexión exitosa</title>
<style>body{font-family:system-ui,sans-serif;display:flex;align-items:center;justify-content:center;min-height:100vh;margin:0;background:#f0fdf4}
.card{background:white;padding:3rem;border-radius:1rem;box-shadow:0 4px 24px rgba(0,0,0,.08);text-align:center;max-width:420px}
h1{color:#059669;margin:0 0 1rem}p{color:#64748b;line-height:1.6;margin:0 0 1.5rem}
a{display:inline-block;background:#0d9488;color:white;padding:.75rem 2rem;border-radius:.5rem;text-decoration:none;font-weight:600}
a:hover{background:#0f766e}</style>
</head><body><div class="card">
<h1>✓ Conectado</h1>
<p>Tu tienda <strong>${shopName}</strong> se ha conectado correctamente a Katalync.</p>
<p>Ya puedes sincronizar tus productos.</p>
<a href="${APP_URL}#sync">Volver a Katalync</a>
</div></body></html>`;

  return [{ json: { error: false, html } }];

} catch (e) {
  return [{ json: { error: true, html: `<h1>Error inesperado</h1><p>${e.message}</p>` } }];
}
